mapper.select:
SELECT COUNT(*)
FROM course c
JOIN teacher t ON c.TeacherID = t.TeacherID
WHERE 1=1

    AND c.course_no = #{course_no}


    AND c.course_name LIKE CONCAT('%', #{course_name}, '%')


    AND c.credit = #{credit}


    AND c.day_of_week = #{day_of_week}


    AND c.time_slot = #{time_slot}


    AND t.teacher_name LIKE CONCAT('%', #{teacher_name}, '%')
